sql:
SELECT AVG(coding_rate) AS average_coding_rate
FROM compression_tests
WHERE algorithm_id = 1;

external_knowledge:
- "stormiest sea" refers to the longest total time taken for the compression process;
- "most experienced hands" refers to the role of users who have conducted compression tests;
- "longest adventure" refers to the maximum total time;
- "average mastery of their craft" refers to the average time spent coding during the compression process.

sql:
SELECT users.user_name, compression_tests.test_date
FROM users
JOIN compression_tests ON users.user_id = compression_tests.user_id;

SELECT DISTINCT set_name
FROM image_sets
INNER JOIN compression_tests ON image_sets.image_set_id = compression_tests.image_set_id;

SELECT u.user_name, u.role, u.email
FROM users u
INNER JOIN compression_tests ct ON u.user_id = ct.user_id;

SELECT user_name
FROM users
WHERE user_id IN (SELECT user_id FROM compression_tests);

SELECT COUNT(test_id) 
FROM compression_tests
WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT set_name, set_description, set_size 
FROM image_sets
WHERE image_set_id = 1001;

SELECT image_name
FROM compression_tests
WHERE psnr > 30;

SELECT DISTINCT u.user_id, u.user_name
FROM users u
JOIN compression_tests ct ON u.user_id = ct.user_id;

SELECT file_name
FROM image_files
WHERE file_size > 10;

SELECT test_id, image_name 
FROM compression_tests 
WHERE test_id IN (1, 2, 3, 4, 5);

SELECT image_name, psnr
FROM compression_tests
WHERE psnr = (SELECT MAX(psnr) FROM compression_tests);
